det_check_template:
proof fn det_take<V>(self_: &PCell<V>, pre_perm: PointsTo<V>, post1_perm: PointsTo<V>, r1: V, post2_perm: PointsTo<V>, r2: V)
    requires (self_.id() == pre_perm@.pcell), (pre_perm.is_init()),
    ensures
        ({
            &&& (post1_perm.id() == pre_perm@.pcell)
            &&& (post1_perm.mem_contents() == MemContents::Uninit)
            &&& (r1 == pre_perm.value())
            &&& (post2_perm.id() == pre_perm@.pcell)
            &&& (post2_perm.mem_contents() == MemContents::Uninit)
            &&& (r2 == pre_perm.value())
        }) ==> det_take_equal::<V>(r1, r2, post1_perm, post2_perm),
{
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_take_equal<V>(r1: V, r2: V, post1_perm: PointsTo<V>, post2_perm: PointsTo<V>) -> bool {
    (r1 == r2)
    && (((post1_perm).is_init() == (post2_perm).is_init()) && ((post1_perm).ptr().addr() == (post2_perm).ptr().addr()) && ((post1_perm).is_init() ==> ((post1_perm).value() == (post2_perm).value())))
}
